// §156 Validate Context / §298 fail-fast input contract.
// Delegates to src/reasoning/wf003.py::_validate_context in the reference impl.
for (const item of items) {
  const cp = item.json;
  for (const f of ['contextId','requirement','knowledgeUnits','evidence','citations']) {
    if (!(f in cp)) { throw new Error('Context Package missing field: ' + f); }
  }
}
return items;

// R-11: derive complianceLevel deterministically (§480/§481).
// R-10: compute authoritative confidence on the platform (§483/§89).
// Reference implementation: src/reasoning/compliance_level.py + confidence.py.
// This node calls the platform reasoning service; no LLM value is authoritative.
return items;

// R-06: attach citations re-linked via evidenceId (§88/§291).
// Reference implementation: src/reasoning/enterprise_llm.py::relink_citations.
return items;
